#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int N;
    scanf("%d", &N);
    int* A = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    int* visited = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        visited[i] = 0;
    }
    int count = 0;
    for (int i = 0; i < N; i++) {
        if (!visited[i]) {
            count++;
            visited[i] = 1;
            for (int j = i + 1; j < N; j++) {
                if (gcd(A[i], A[j]) == 1) {
                    if (!visited[j]) {
                        visited[j] = 1;
                    }
                }
            }
        }
    }
    printf("%d\n", count);
    free(A);
    free(visited);
    return 0;
}

