import java.util.Scanner;
public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = scanner.nextInt();
        }
        int[] visited = new int[N];
        int count = 0;
        for (int i = 0; i < N; i++) {
            if (visited[i] == 0) {
                count++;
                visited[i] = 1;
                for (int j = i + 1; j < N; j++) {
                    if (gcd(A[i], A[j]) == 1) {
                        if (visited[j] == 0) {
                            visited[j] = 1;
                        }
                    }
                }
            }
        }
        System.out.println(count);
    }
}

